28	Optional<Shape> GetDiscoWorkerCPUBinding(int num_workers) {
29	  const char* raw_cpu_binding = std::getenv("MLC_DISCO_WORKER_CPU_BINDING");
30	  if (raw_cpu_binding == nullptr) {
31	    return std::nullopt;
32	  }
33	
34	  std::string cpu_binding_str(raw_cpu_binding);
35	  std::vector<std::string> cpu_ids_str = Split(cpu_binding_str, ',');
36	  std::vector<int64_t> cpu_ids;
37	  for (const std::string& cpu_id_str : cpu_ids_str) {
38	    try {
39	      cpu_ids.push_back(std::stol(cpu_id_str));
40	    } catch (std::invalid_argument const& ex) {
41	      LOG(FATAL) << "Invalid MLC_DISCO_WORKER_CPU_BINDING \"" << cpu_binding_str << "\"";
42	    }
43	  }
44	  if (static_cast<int>(cpu_ids.size()) < num_workers) {
45	    LOG(FATAL) << "Insufficient number of specified CPU workers in MLC_DISCO_WORKER_CPU_BINDING, "
46	                  "expecting at least "
47	               << num_workers << "CPU ids but only " << cpu_ids.size() << " are given.";
48	  }
49	
50	  return Shape{cpu_ids};
51	}
