53	Function FunctionTable::SessionFuncAsPackedFunc(Session sess, DRef sess_func, String name) {
54	  return Function([sess, func = std::move(sess_func), name = std::move(name)](
55	                      ffi::PackedArgs args, ffi::Any* rv) -> void {
56	    std::vector<AnyView> packed_args(args.size() + 3);
57	    packed_args[0] = static_cast<int>(DiscoAction::kCallPacked);
58	    packed_args[1] = 0;
59	    packed_args[2] = func;
60	    for (int i = 0; i < args.size(); ++i) {
61	      packed_args[i + 3] = args[i];
62	    }
63	    *rv = sess->CallWithPacked(tvm::ffi::PackedArgs(packed_args.data(), packed_args.size()));
64	  });
65	}
