67	void FunctionTable::Init(String reload_lib_path, Device device, tvm::ffi::json::Object model_config,
68	                         Optional<Session> session, int num_shards, int num_stages) {
69	  local_gpu_device = device;
70	  this->model_config = model_config;
71	  this->cached_buffers = Map<String, ObjectRef>();
72	
73	  int num_workers = num_shards * num_stages;
74	  if (num_workers > 1) {
75	    TVM_FFI_ICHECK(session.has_value());
76	    this->sess = session.value();
77	    this->use_disco = true;
78	    this->disco_mod = sess->CallPacked(sess->GetGlobalFunc("runtime.disco.load_vm_module"),
79	                                       reload_lib_path, Optional<Device>(std::nullopt));
80	    this->mod_get_func = [this, fmodule_get_function = sess->GetGlobalFunc(
81	                                    "ffi.ModuleGetFunction")](const std::string& name) -> Function {
82	      DRef func = sess->CallPacked(fmodule_get_function, this->disco_mod, name, true);
83	      bool exists = (func->DebugGetFromRemote(0).as<Function>()) != nullptr;
84	      if (!exists) {
85	        return Function(nullptr);
86	      }
87	      return SessionFuncAsPackedFunc(sess, func, name);
88	    };
89	    if (num_stages == 1) {
90	      if (Optional<Shape> cpu_ids = GetDiscoWorkerCPUBinding(/*num_workers=*/num_shards)) {
91	        Shape cpu_ids_value = cpu_ids.value();
92	        sess->CallPacked(sess->GetGlobalFunc("runtime.disco.bind_worker_to_cpu_core"),
93	                         cpu_ids_value);
94	      }
95	    }
96	    this->get_global_func = [this](const std::string& name) -> Function {
97	      return SessionFuncAsPackedFunc(sess, sess->GetGlobalFunc(name), name);
98	    };
99	    this->model_metadata_ = ModelMetadata::FromModule(
100	        this->disco_mod.value()->DebugGetFromRemote(0).cast<Module>(), std::move(model_config));
101	    this->_InitFunctions();
102	  } else {
103	    TVM_FFI_ICHECK(!session.has_value());
104	    Optional<Module> executable = std::nullopt;
105	    Optional<Function> fload_exec;
106	    if (StartsWith(reload_lib_path, "system://")) {
107	      static Function f_load_system_lib = Function::GetGlobalRequired("ffi.SystemLib");
108	      std::string system_lib_prefix = std::string(reload_lib_path).substr(9);
109	      std::replace(system_lib_prefix.begin(), system_lib_prefix.end(), /*old=*/'-', /*new=*/'_');
110	      executable = f_load_system_lib(system_lib_prefix + "_").cast<Module>();
111	      fload_exec = executable.value()->GetFunction("vm_load_executable");
112	      TVM_FFI_ICHECK(fload_exec.has_value())
113	          << "Cannot find system lib with " << system_lib_prefix
114	          << ", please make sure you set model_lib field consistently with the compilation ";
115	    } else {
116	      executable = tvm::ffi::Module::LoadFromFile(reload_lib_path);
117	      fload_exec = executable.value()->GetFunction("vm_load_executable");
118	      /* precompile opencl kernel programs */
119	      if (device.device_type == kDLOpenCL) {
120	        auto f_get = executable.value()->GetFunction("opencl.GetPreCompiledPrograms", true);
121	        TVM_FFI_ICHECK(f_get.has_value()) << "Cannot find opencl.GetPreCompiledPrograms";
122	        tvm::ffi::String bytes = f_get.value()().cast<String>();
123	        auto f_set = executable.value()->GetFunction("opencl.SetPreCompiledPrograms", true);
124	        TVM_FFI_ICHECK(f_set.has_value()) << "Cannot find opencl.SetPreCompiledPrograms";
125	        f_set.value()(tvm::ffi::String(bytes));
126	      }
127	      TVM_FFI_ICHECK(fload_exec.has_value()) << "TVM runtime cannot find vm_load_executable";
128	    }
129	    this->use_disco = false;
130	    this->local_vm = fload_exec.value()().cast<Module>();
131	    this->local_vm.value()
132	        ->GetFunction("vm_initialization")
133	        .value()(static_cast<int>(device.device_type), device.device_id,
134	                 static_cast<int>(tvm::runtime::memory::AllocatorType::kPooled),
135	                 static_cast<int>(kDLCPU), 0,
136	                 static_cast<int>(tvm::runtime::memory::AllocatorType::kPooled));
137	    this->mod_get_func = [this](const std::string& name) -> Function {
138	      return this->local_vm.value()->GetFunction(name, true).value_or(Function(nullptr));
139	    };
140	    this->get_global_func = [](const std::string& name) -> Function {
141	      return Function::GetGlobalRequired(name);
142	    };
143	    this->model_metadata_ =
144	        ModelMetadata::FromModule(this->local_vm.value(), std::move(model_config));
145	    this->_InitFunctions();
146	  }
147	  TVM_FFI_ICHECK_EQ(this->model_metadata_.tensor_parallel_shards, num_shards);
148	  TVM_FFI_ICHECK_EQ(this->model_metadata_.pipeline_parallel_stages, num_stages);
149	  // Invoke the CUDA graph allocation init function if it is defined.
150	  if (cuda_graph_alloc_init_func_.defined()) {
151	    this->cuda_graph_alloc_init_func_();
152	  }
153	}
