155	ObjectRef FunctionTable::LoadParams(const std::string& model_path, Device device) {
156	  if (this->use_disco) {
157	    Optional<DRef> params = std::nullopt;
158	    if (this->model_metadata_.params.empty()) {
159	      std::filesystem::path fs_model_path = model_path;
160	      std::string metadata_path = (fs_model_path / "tensor-cache.json").string();
161	      std::string tensor_cache_metadata = LoadBytesFromFile(metadata_path);
162	      Function loader_create = this->get_global_func("runtime.disco.ShardLoader");
163	
164	      auto load_all_func_name = "runtime.disco.ShardLoaderLoadAll";
165	      Function loader_load_all = this->get_global_func(load_all_func_name);
166	      TVM_FFI_ICHECK(loader_create != nullptr);
167	      TVM_FFI_ICHECK(loader_load_all != nullptr);
168	      DRef loader =
169	          loader_create(metadata_path, tensor_cache_metadata, "", this->disco_mod).cast<DRef>();
170	      params = loader_load_all(loader).cast<DRef>();
171	    } else {
172	      auto load_func_name = getenv("MLC_INTERNAL_PRESHARD_NUM") == nullptr
173	                                ? "mlc.multi_gpu.LoadMultiGPU"
174	                                : "mlc.multi_gpu.LoadMultiGPUPresharded";
175	      Function loader = this->get_global_func(load_func_name);
176	      params = loader(model_path, this->disco_mod, tvm::ffi::json::Stringify(this->model_config))
177	                   .cast<DRef>();
178	    }
179	    return params.value();
180	  } else {
181	    static Function fload_cache = Function::GetGlobalRequired("vm.builtin.tensor_cache.load");
182	    fload_cache(model_path, static_cast<int32_t>(device.device_type), device.device_id);
183	    Array<Tensor> params;
184	    if (this->model_metadata_.params.empty()) {
185	      constexpr const char* name_loader = "vm.builtin.param_array_from_cache";
186	      static Function fload_params = Function::GetGlobalRequired(name_loader);
187	      params = fload_params("param", -1).cast<Array<Tensor>>();
188	    } else {
189	      constexpr const char* name_loader = "vm.builtin.param_array_from_cache_by_name";
190	      static Function fload_params = Function::GetGlobalRequired(name_loader);
191	      Array<String> param_names;
192	      param_names.reserve(this->model_metadata_.params.size());
193	      for (const auto& param : this->model_metadata_.params) {
194	        param_names.push_back(param.name);
195	      }
196	      params = fload_params(param_names).cast<Array<Tensor>>();
197	    }
198	    // after we get params, it is safe to simply clear the cached version
199	    // as these params are referenced by params_
200	    static Function fclear_tensor_cache =
