309	ObjectRef FunctionTable::CopyToWorker0(const Tensor& host_array, String buffer_cache_key,
310	                                       Shape max_reserved_shape, bool local_only) {
311	  Map<String, ObjectRef> cached_buffers = this->cached_buffers.value();
312	  if (this->use_disco && !local_only) {
313	    Device null_device{DLDeviceType(0), 0};
314	    Optional<DRef> buffer = std::nullopt;
315	    auto it = cached_buffers.find(buffer_cache_key);
316	    if (it != cached_buffers.end()) {
317	      buffer = (*it).second.as_or_throw<DRef>();
318	    } else {
319	      buffer = this->Empty(max_reserved_shape, host_array.DataType(), null_device,
320	                           /*worker0_only=*/false)
321	                   .as_or_throw<DRef>();
322	      cached_buffers.Set(buffer_cache_key, buffer.value());
323	    }
324	    Shape real_shape = host_array.Shape();
325	    DRef buffer_view = nd_view_func_(buffer.value(), real_shape).cast<DRef>();
326	    sess->CopyToWorker0(host_array, buffer_view);
327	    return buffer_view;
328	  } else {
329	    auto it = cached_buffers.find(buffer_cache_key);
330	    Tensor buffer{nullptr};
331	    if (it != cached_buffers.end()) {
332	      buffer = (*it).second.as_or_throw<Tensor>();
333	      if (buffer_cache_key == "image") {
334	        if (tvm::ffi::GetDataSize(*buffer.operator->()) <
335	            tvm::ffi::GetDataSize(*host_array.operator->())) {
336	          buffer = Tensor::Empty(max_reserved_shape, host_array->dtype, local_gpu_device);
337	          cached_buffers.Set(buffer_cache_key, buffer);
338	        }
339	      }
340	    } else {
341	      buffer = Tensor::Empty(max_reserved_shape, host_array->dtype, local_gpu_device);
342	      cached_buffers.Set(buffer_cache_key, buffer);
343	    }
344	    buffer = buffer.CreateView(host_array.Shape(), host_array->dtype);
345	    DLTensor copy_dst = *(buffer.operator->());
346	    Tensor::CopyFromTo(host_array.operator->(), &copy_dst);
347	    return buffer;
348	  }
