244	
245	  Tensor BatchPrefill(const ObjectRef& embeddings, const std::vector<int64_t>& seq_ids,
246	                      const std::vector<int>& lengths) final {
247	    TVM_FFI_ICHECK(!seq_ids.empty());
248	    TVM_FFI_ICHECK_EQ(seq_ids.size(), lengths.size());
249	    int num_sequences = seq_ids.size();
250	    int total_length = 0;
251	
252	    int* p_logit_pos = static_cast<int*>(logit_pos_arr_->data);
253	    for (int i = 0; i < num_sequences; ++i) {
254	      total_length += lengths[i];
255	      p_logit_pos[i] = total_length - 1;
256	    }
257	    bool padded = total_length % seqlen_padding_factor_ != 0;
258	    if (padded) {
259	      total_length = (total_length + seqlen_padding_factor_ - 1) / seqlen_padding_factor_ *
260	                     seqlen_padding_factor_;
261	    }
262	    NVTXScopedRange nvtx_scope("BatchPrefill num_seq=" + std::to_string(num_sequences) +
263	                               " total_len=" + std::to_string(total_length));
264	    Tensor logit_pos_nd = logit_pos_arr_.CreateView({num_sequences}, DLDataType{kDLInt, 32, 1});
265	
266	    TVM_FFI_ICHECK(ft_.prefill_func_.defined())
267	        << "`prefill_with_embed` function is not found in the model. Please make sure the model is "
268	           "compiled with flag `--sep-embed` and `--enable-batching`";
269	    TVM_FFI_ICHECK(ft_.kv_cache_begin_forward_func_.defined());
270	    TVM_FFI_ICHECK(ft_.kv_cache_end_forward_func_.defined());
271	    TVM_FFI_ICHECK(kv_cache_.defined()) << "KV cache has not been initialized.";
272	
273	    // Begin forward with the sequence ids and new lengths.
